mapper.select:
SELECT COUNT(*)
FROM products p
WHERE 1=1
  AND p.active = 'Y'
  AND p.apv_stat_cd = '승인'


    AND p.prod_type IN ('FOREIGN_DEP', 'FOREIGN_SAV')



    AND p.rate_cat = #{rateCategory}



    AND (
        p.tgt_lrg = #{targetLarge}
        OR p.tgt_lrg = 'ALL'
    )



    AND (
        p.tgt_dtl = #{targetDetail}
        OR p.tgt_dtl = 'ALL'
    )



    AND p.prod_type = #{productType}



    AND (
        p.prod_nm LIKE '%' || #{keyword} || '%'
        OR DBMS_LOB.INSTR(p.prod_desc, #{keyword}) > 0
    )

SELECT prod_no AS product_id, prod_nm AS product_name, prod_type AS product_type, apv_stat_cd AS approve_status, reg_dt AS create_date, reg_by AS created_by, tgt_lrg AS target_large, tgt_dtl AS target_detail, rate_cat AS rate_category, min_prd_mon AS min_period_month, max_prd_mon AS max_period_month FROM PRODUCTS WHERE 1=1
AND prod_nm LIKE '%' || #{keyword} || '%'
AND prod_type = #{type}
AND apv_stat_cd = #{status}
ORDER BY prod_no DESC OFFSET #{offset} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
FROM products
WHERE 1=1


    AND prod_nm LIKE '%' || #{keyword} || '%'



    AND prod_type = #{type}



    AND apv_stat_cd = #{status}
